create table ra_hosts
(
    id           bigint auto_increment
        primary key,
    employee_ref varchar(80)                           null,
    full_name    varchar(160)                          not null,
    area_name    varchar(120)                          null,
    email        varchar(160)                          null,
    phone_number unknown null,
    status       varchar(20) default 'ACTIVE'          not null,
    search_alias varchar(255)                          null,
    created_at   datetime    default CURRENT_TIMESTAMP not null,
    updated_at   datetime    default CURRENT_TIMESTAMP not null on update CURRENT_TIMESTAMP
)
    collate = utf8mb4_unicode_ci;

create index idx_ra_hosts_full_name
    on ra_hosts (full_name);

create index idx_ra_hosts_status_full_name
    on ra_hosts (status, full_name);

